final class DemoLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()
    @Published var lastLocation: CLLocationCoordinate2D? = nil

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyBest
    }

    func requestPermission() {
        manager.requestWhenInUseAuthorization()
        manager.startUpdatingLocation()
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        lastLocation = locations.last?.coordinate
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {}
}

struct GoogleMapView: UIViewRepresentable {
    let places: [DemoPlace]
    @Binding var selectedPlace: DemoPlace?
    let userLocation: CLLocationCoordinate2D?

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: places.first?.lat ?? 37.4220,
                                              longitude: places.first?.lng ?? -122.0841,
                                              zoom: 11)
        let mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.delegate = context.coordinator

        for place in places {
            let marker = GMSMarker(position: CLLocationCoordinate2D(latitude: place.lat, longitude: place.lng))
            marker.title = place.name
            marker.snippet = place.address
            marker.userData = place
            marker.map = mapView
        }
        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        if let selectedPlace {
            uiView.animate(toLocation: CLLocationCoordinate2D(latitude: selectedPlace.lat, longitude: selectedPlace.lng))
            uiView.animate(toZoom: 13)
        } else if let userLocation {
            uiView.animate(toLocation: userLocation)
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    final class Coordinator: NSObject, GMSMapViewDelegate {
        let parent: GoogleMapView
        init(_ parent: GoogleMapView) { self.parent = parent }

        func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
            if let place = marker.userData as? DemoPlace {
                parent.selectedPlace = place
                mapView.selectedMarker = marker
                return true
            }
            return false
        }
    }
}

struct StripeCheckoutView: View {
    let place: DemoPlace
    let onComplete: (String) -> Void

    @Environment(\.dismiss) private var dismiss
    @State private var paymentSheet: PaymentSheet?
    @State private var isLoading = true
    @State private var statusText = "Preparing secure checkout..."

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Text(place.name)
                    .font(.title2)
