                Text(place.address)
                    .multilineTextAlignment(.center)
                    .foregroundColor(.secondary)
                Text(String(format: "Amount: $%.2f", place.price))
                    .font(.headline)

                if isLoading {
                    ProgressView()
                    Text(statusText)
                        .font(.footnote)
                        .foregroundColor(.secondary)
                } else {
                    Button {
                        Task { await presentPaymentSheet() }
                    } label: {
                        Text("Complete Payment")
                            .frame(maxWidth: .infinity)
                            .padding()
                            .background(Color.green)
                            .foregroundColor(.white)
                            .cornerRadius(12)
                    }
                    .padding(.horizontal)
                }

                Spacer()
            }
            .padding()
            .navigationTitle("Stripe Checkout")
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Close") {
                        dismiss()
                    }
                }
            }
            .onAppear {
                Task { await prepareCheckout() }
            }
        }
    }

    private func prepareCheckout() async {
        isLoading = true
        statusText = "Creating demo payment session..."

        let customerId = "cus_demo_123"
        let ephemeralKeySecret = "ek_test_demo_123"
        let clientSecret = "pi_demo_123_secret_demo"

        let configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Investor Demo"
        configuration.customer = .init(id: customerId, ephemeralKeySecret: ephemeralKeySecret)
        configuration.applePay = .init(merchantId: "merchant.com.investordemo")

        paymentSheet = PaymentSheet(paymentIntentClientSecret: clientSecret, configuration: configuration)
        isLoading = false
        statusText = "Ready"
    }

    private func presentPaymentSheet() async {
        guard let paymentSheet else { return }
        paymentSheet.present(from: UIApplication.shared.topMostViewController() ?? UIViewController()) { result in
            switch result {
            case .completed:
                onComplete("Payment completed successfully for \(place.name)")
                dismiss()
            case .canceled:
                onComplete("Payment canceled")
            case .failed(let error):
                onComplete("Payment failed: \(error.localizedDescription)")
            }
        }
    }
}

extension UIApplication {
    func topMostViewController(base: UIViewController? = nil) -> UIViewController? {
        let base = base ?? connectedScenes
            .compactMap { $0 as? UIWindowScene }
            .flatMap { $0.windows }
            .first { $0.isKeyWindow }?.rootViewController

        if let nav = base as? UINavigationController {
            return topMostViewController(base: nav.visibleViewController)
        }
        if let tab = base as? UITabBarController {
            return topMostViewController(base: tab.selectedViewController)
        }
        if let presented = base?.presentedViewController {
            return topMostViewController(base: presented)
        }
        return base
    }
}